.darma-loader-darma-custom-508 {color: var(--loader-color, #be123c);
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #be123c);
   box-shadow: 30px 0 var(--loader-secondary-color, #fda4af);
   animation: darma-loader-darma-custom-508-l4-1 1s infinite alternate, darma-loader-darma-custom-508-l4-2 .5s infinite alternate;
}
@keyframes darma-loader-darma-custom-508-l4-1  {
  0%,40% {transform: rotate(0)}
80%,100% {transform: rotate(.5turn)}
}
@keyframes darma-loader-darma-custom-508-l4-2  {
  80%,100% {box-shadow: 16px 0 var(--loader-secondary-color, #fda4af)}
}

